import akka.actor.ActorSystem
import akka.http.scaladsl.Http
import akka.http.scaladsl.model._
import akka.stream.Materializer
import spray.json._

object WebhookProxyService {
  def main(args: Array[String]): Unit = {
    implicit val system = ActorSystem("webhook-proxy")
    implicit val materializer = Materializer(system)

    val bindingFuture = Http().bindAndHandle({
      case HttpRequest(HttpMethods.POST, _, entity, _) =>
        val userUrl = entity.asString
        val responseFuture = Http().singleRequest(HttpRequest(uri=userUrl))
        onComplete(responseFuture) {
          case Success(res) => HttpResponse(StatusCodes.OK, entity=res.entity)
          case Failure(ex)  => HttpResponse(StatusCodes.InternalServerError, entity=JsObject("error" -> ex.getMessage))
        }
      case _ => HttpResponse(StatusCodes.NotImplemented)
    }, "localhost", 8080)

    bindingFuture.foreach { _ =>
      println(s"Server online at http://localhost:8080/")
    }
  }
}